// Verify /api/directions returns 400 when lat/lon are missing — caught by schema validation
async function testDirectionsMissingParams() {
  const res = await fetch('http://localhost:3001/api/directions');
  assertEquals(res.status, 400);
  const body = await res.json();
  assertEquals(body.error, 'Validation failed');
  assert(body.details.length > 0, 'Should include validation detail messages');
}
